        expected_y[99][3] = 64'h5667a71f8bb73455;
        expected_y[99][4] = 64'h391dede2024f4f19;
        expected_y[99][5] = 64'h0000000000000001;

    @(posedge tb_clk); // one warm-up edge
    for (run_idx = 0; run_idx < NUM_RUNS; run_idx = run_idx + 1) begin
        
        #(2.1 * CLK_PERIOD);
        tb_rst = 1'b1;
        #(2 * CLK_PERIOD);

        for (word_idx = 0; word_idx < SEED_WORDS;
             word_idx = word_idx + 1) begin
            DUT.key_sign_mem_inst.mem[`SK_SEED_ADDR + word_idx]
                = seed_sk[run_idx][word_idx];
            DUT.key_sign_mem_inst.mem[`PK_SEED_ADDR + word_idx]
                = seed_pk[run_idx][word_idx];
        end
        tb_rst = 1'b0;

        tb_start = `START_KEYGEN;
        #(CLK_PERIOD);
        tb_start = '0;

        wait (tb_done === 1'b1);
        #1;

        for (word_idx = 0; word_idx < Y_WORDS;
             word_idx = word_idx + 1) begin
            if (DUT.key_sign_mem_inst.mem[`Y_ADDR + word_idx]
                    !== expected_y[run_idx][word_idx]) begin
                $fatal(1,
                    "Keygen run %0d y word %0d incorrect: got %016h, expected %016h",
                    run_idx, word_idx,
                    DUT.key_sign_mem_inst.mem[`Y_ADDR + word_idx],
                    expected_y[run_idx][word_idx]);
            end
        end
        $display("Keygen run %0d/%0d correct", run_idx + 1, NUM_RUNS);
    end

    $display("All %0d keygen y vectors correct", NUM_RUNS);
    $finish;
end

